const { Pool } = require('pg');

const pool = new Pool({
  user: process.env.DB_USER || 'app_user',
  host: process.env.DB_HOST || 'localhost',
  database: process.env.DB_NAME || 'myapp_db',
  password: process.env.DB_PASSWORD,
  port: process.env.DB_PORT || 5432,
  max: 20,
  idleTimeoutMillis: 30000,
  connectionTimeoutMillis: 2000,
});

const usersAPI = {
  async create(userData) {
    const { name, email, role } = userData;
    const result = await pool.query(
      'INSERT INTO users (name, email, role, created_at) VALUES ($1, $2, $3, NOW()) RETURNING *',
      [name, email, role]
    );
    return result.rows[0];
  },

  async getAll() {
    const result = await pool.query('SELECT id, name, email, role, created_at FROM users ORDER BY id');
    return result.rows;
  },

  async getById(id) {
    const result = await pool.query('SELECT id, name, email, role, created_at FROM users WHERE id = $1', [id]);
    return result.rows[0];
  },

  async update(id, userData) {
    const { name, email, role } = userData;
    const result = await pool.query(
      'UPDATE users SET name = $1, email = $2, role = $3, updated_at = NOW() WHERE id = $4 RETURNING *',
      [name, email, role, id]
    );
    return result.rows[0];
  },

  async delete(id) {
    const result = await pool.query('DELETE FROM users WHERE id = $1 RETURNING *', [id]);
    return result.rows[0];
  }
};

